INSERT INTO "public"."faqs" ("id", "question", "answer", "sort_order", "created_at") VALUES ('cf44b42e-b148-4125-802a-a9cef4ec4891', 'Como recebo meu código?', 'O código é enviado automaticamente para seu WhatsApp e E-mail assim que o pagamento é confirmado.', 1, '2025-12-29 06:17:48.237502+00'), ('e6bdf0af-7cc0-465d-bb58-fe0c5c162946', 'O código funciona em contas dos EUA?', 'Depende do produto. Verifique a região indicada na descrição ("Global", "US", "MZ") antes de comprar.', 3, '2025-12-29 06:17:48.237502+00'), ('eab862d6-efbc-457f-8b82-17ffca727c9e', 'Posso pagar com M-Pesa ou E-mola?', 'Sim! Aceitamos M-Pesa, E-Mola e cartões de crédito/débito.', 2, '2025-12-29 06:17:48.237502+00');

